  "help.delete_failed_email": "ಸ್ವಯಂಚಾಲಿತವಾಗಿ ಅಳಿಸಲು ಸಾಧ್ಯವಾಗಲಿಲ್ಲ — ಬೆಂಬಲಕ್ಕೆ ಇಮೇಲ್ ತೆರೆಯಲಾಗಿದೆ",
  "help.delete_email_subject": "ಖಾತೆ ಅಳಿಸುವಿಕೆ ವಿನಂತಿ",
  "help.delete_email_body": "ನಮಸ್ಕಾರ ScanIQ ಬೆಂಬಲದವರೇ,\n\nನನ್ನ ಖಾತೆಯನ್ನು ಅಳಿಸಲು ನಾನು ಬಯಸುತ್ತೇನೆ.\nಬಳಕೆದಾರ ID: {id}\nಇಮೇಲ್: {email}\n\nಧನ್ಯವಾದಗಳು.",
  "help.export_done": "ನಿಮ್ಮ ಡೇಟಾವನ್ನು ಡೌನ್‌ಲೋಡ್ ಮಾಡಲಾಗಿದೆ",
  "help.export_failed": "ಡೇಟಾವನ್ನು ರಫ್ತು ಮಾಡಲು ಸಾಧ್ಯವಾಗಲಿಲ್ಲ",
  "help.remove": "ತೆಗೆದುಹಾಕಿ",
  "help.faq_q1": "ನಾನು ಆಹಾರವನ್ನು ಹೇಗೆ ಸ್ಕ್ಯಾನ್ ಮಾಡುವುದು?",
  "help.faq_a1": "ಪರದೆಯ ಕೆಳಭಾಗದಲ್ಲಿರುವ ದೊಡ್ಡ ಕಿತ್ತಳೆ ಸ್ಕ್ಯಾನ್ ಬಟನ್ ಅನ್ನು ಟ್ಯಾಪ್ ಮಾಡಿ. ನಿಮ್ಮ ಊಟದ ಫೋಟೋ ತೆಗೆದುಕೊಳ್ಳಿ ಮತ್ತು ಅಪ್ಲಿಕೇಶನ್ ಕ್ಯಾಲೋರಿಗಳು ಮತ್ತು ಪೋಷಕಾಂಶಗಳನ್ನು ಸ್ವಯಂಚಾಲಿತವಾಗಿ ವಿಶ್ಲೇಷಿಸುತ್ತದೆ. ಫಲಿತಾಂಶಗಳು ಅಂದಾಜುಗಳು.",
  "help.faq_q2": "ನನ್ನ ಡೇಟಾ ಖಾಸಗಿಯೇ?",
  "help.faq_a2": "ಹೌದು. ನಾವು GDPR ಅನ್ನು ಅನುಸರಿಸುತ್ತೇವೆ. ನಿಮ್ಮ ಡೇಟಾವನ್ನು ಸುರಕ್ಷಿತವಾಗಿ ಸಂಗ್ರಹಿಸಲಾಗಿದೆ, ಎಂದಿಗೂ ಮಾರಾಟ ಮಾಡಲಾಗುವುದಿಲ್ಲ ಮತ್ತು ನೀವು ಯಾವುದೇ ಸಮಯದಲ್ಲಿ ನಿಮ್ಮ ಖಾತೆಯನ್ನು ಅಳಿಸಬಹುದು.",
  "help.faq_q3": "ನಾನು ಪ್ರೀಮಿಯಂಗೆ ಹೇಗೆ ಅಪ್‌ಗ್ರೇಡ್ ಮಾಡುವುದು?",
  "help.faq_a3": "ಪ್ರೊಫೈಲ್ → Go Premium ಗೆ ಹೋಗಿ. ಪ್ರೀಮಿಯಂ ನಿಮಗೆ ಅನಿಯಮಿತ ಸ್ಕ್ಯಾನ್‌ಗಳು, AI ಊಟದ ಸಲಹೆಗಳು ಮತ್ತು ಸುಧಾರಿತ ವಿಶ್ಲೇಷಣೆಗಳನ್ನು ನೀಡುತ್ತದೆ. ಚಂದಾದಾರಿಕೆಗಳನ್ನು Apple App Store ಮತ್ತು Google Play ನಿಂದ ಪ್ರಕ್ರಿಯೆಗೊಳಿಸಲಾಗುತ್ತದೆ.",
  "help.faq_q4": "ಸ್ಕ್ಯಾನ್ ಎಷ್ಟು ನಿಖರವಾಗಿದೆ?",
  "help.faq_a4": "ಸ್ಕ್ಯಾನರ್ ಸಾಮಾನ್ಯ ಆಹಾರಗಳಿಗೆ ಉತ್ತಮ ಅಂದಾಜುಗಳನ್ನು ನೀಡುತ್ತದೆ, ಆದರೆ ಫಲಿತಾಂಶಗಳು ಅಂದಾಜುಗಳಾಗಿವೆ ಮತ್ತು ಬದಲಾಗಬಹುದು. ಸ್ಕ್ಯಾನ್ ಮಾಡಿದ ನಂತರ ನೀವು ಯಾವಾಗಲೂ ಭಾಗದ ಗಾತ್ರ ಮತ್ತು ಪೋಷಕಾಂಶಗಳನ್ನು ಹಸ್ತಚಾಲಿತವಾಗಿ ಹೊಂದಿಸಬಹುದು.",
  "help.faq_q5": "ScanIQ ವೈದ್ಯಕೀಯ ಸಲಹೆಯಲ್ಲವೇ?",
  "help.faq_a5": "ಇಲ್ಲ. ScanIQ ವೈದ್ಯಕೀಯ ಸಲಹೆಯಲ್ಲ ಮತ್ತು ವೈದ್ಯರು ಅಥವಾ ಆಹಾರ ತಜ್ಞರ ಸಲಹೆಯನ್ನು ಬದಲಿಸುವುದಿಲ್ಲ. ನಿಮ್ಮ ಆಹಾರ ಅಥವಾ ತರಬೇತಿಗೆ ಪ್ರಮುಖ ಬದಲಾವಣೆಗಳನ್ನು ಮಾಡುವ ಮೊದಲು ಆರೋಗ್ಯ ವೃತ್ತಿಪರರೊಂದಿಗೆ ಮಾತನಾಡಿ.",
  "help.faq_q6": "ನಾನು ಅಪ್ಲಿಕೇಶನ್ ಅನ್ನು ಆಫ್‌ಲೈನ್‌ನಲ್ಲಿ ಬಳಸಬಹುದೇ?",
  "help.faq_a6": "ಹೆಚ್ಚಿನ ವೈಶಿಷ್ಟ್ಯಗಳಿಗೆ ಇಂಟರ್ನೆಟ್ ಅಗತ್ಯವಿದೆ ಏಕೆಂದರೆ AI ಸ್ಕ್ಯಾನಿಂಗ್ ಮತ್ತು ಸಿಂಕ್ ಕ್ಲೌಡ್‌ನಲ್ಲಿ ಕಾರ್ಯನಿರ್ವಹಿಸುತ್ತದೆ.",
