const dictionaries: Record<string, Dict> = {
  en, da, de, es, fr, it, nl, pt, sv, zh, hi, ar, bn, ur,
  ja, ko, ru, tr, pl, no, fi, is, id, vi, th, ms,
  uk, sk, cs, ro, be, hu, sr, sl, hr, bs, mk, sq, bg, el, lt, lv, et, mt, ga, cy, eu, ca, gd, gl, lb, fil, fo, sw, ha, ig, yo, af, am, zu, xh, so, rw, sn, mg, fa, ny, he, ps, az, ku, uz, kk, ky, tg, tk, mn, hy, ka, ta, mr, te, gu, ml, kn, pa, as, ne, or, si, km, yue, my, ht, lo, qu, sm, gn, to, mi, haw, fj, eo,
};

export function translate(lang: string, key: TKey): string {
  const exact = dictionaries[lang];
  if (exact && exact[key]) return exact[key]!;
  const base = lang.split("-")[0];
  const baseDict = dictionaries[base];
  if (baseDict && baseDict[key]) return baseDict[key]!;
  return en[key];
}
